class HandlerRegistry:
    def __init__(self):
        self._handlers: Dict[str, Type[MessageHandler]] = {}

    def register(self, message_type: str, handler_class: Type[MessageHandler]):
        self._handlers[message_type] = handler_class
        logger.info(f"Registered handler '{handler_class.__name__}' for message type '{message_type}'")

    def unregister(self, message_type: str):
        if message_type in self._handlers:
            del self._handlers[message_type]
            logger.info(f"Unregistered handler for message type '{message_type}'")

    def get_handler(self, message_type: str) -> Optional[MessageHandler]:
        handler_class = self._handlers.get(message_type)
        if handler_class:
            return handler_class()
        return None

    def get_registered_types(self) -> List[str]:
        return list(self._handlers.keys())


class DeadLetterQueueManager:
    def __init__(self, sqs_client, dlq_url: str):
        self.sqs_client = sqs_client
        self.dlq_url = dlq_url

    def send_to_dlq(self, job_message: JobMessage, error: str):
        try:
            dlq_body = {
                'original_message_id': job_message.message_id,
                'message_type': job_message.message_type,
                'payload': job_message.payload,
                'error': error,
                'retry_count': job_message.retry_count,
                'failed_at': datetime.utcnow().isoformat(),
            }
            self.sqs_client.send_message(
                QueueUrl=self.dlq_url,
                MessageBody=json.dumps(dlq_body),
                MessageAttributes={
                    'MessageType': {
                        'DataType': 'String',
                        'StringValue': job_message.message_type,
                    },
                    'ErrorType': {
                        'DataType': 'String',
                        'StringValue': type(error).__name__ if isinstance(error, Exception) else 'ProcessingError',
                    }
                }
            )
            logger.info(f"Message {job_message.message_id} sent to DLQ")
        except ClientError as e:
            logger.error(f"Failed to send message to DLQ: {e}")


